216	export const getParentScrollableElement = (node: HTMLElement) => {
217	  let parentNode: Node | undefined = node;
218	  while (parentNode) {
219	    if (isHTMLElement(parentNode)) {
220	      let overflow = parentNode.style?.overflow;
221	      if (!overflow.includes('scroll') && !overflow.includes('auto')) {
222	        overflow = window.getComputedStyle(parentNode).overflow;
223	      }
224	      if (overflow.includes('scroll') || overflow.includes('auto')) {
225	        return parentNode;
226	      }
227	    }
228	    parentNode = parentNode.parentNode ?? undefined;
229	  }
230	  return undefined;
231	};
